    // roundShortest rounds d (= mant * 2^exp) to the shortest number of digits
    // that will let the original floating point value be precisely reconstructed.
    void roundShortest(struct decimal* d, uint64_t mant, int exp, struct floatInfo* flt)
    {
        // If mantissa is zero, the number is zero; stop now.
        if(mant == 0)
        {
            d->nd = 0;
            return;
        }

        // Compute upper and lower such that any decimal number
        // between upper and lower (possibly inclusive)
        // will round to the original floating point number.
        // We may see at once that the number is already shortest.
        // Suppose d is not denormal, so that 2^exp <= d < 10^dp.
        // The closest shorter number is at least 10^(dp-nd) away.
        // The lower/upper bounds computed below are at distance
        // at most 2^(exp-mantbits).
        // So the number is already shortest if 10^(dp-nd) > 2^(exp-mantbits),
        // or equivalently log2(10)*(dp-nd) > exp-mantbits.
        // It is true if 332/100*(dp-nd) >= exp-mantbits (log2(10) > 3.32).
        // minimum possible exponent
        auto minexp = flt->bias + 1;
        if(exp > minexp && 332 * (d->dp - d->nd) >= 100 * (exp - int(flt->mantbits)))
        {
            // The number is already shortest.
            return;
        }

        // d = mant << (exp - mantbits)
        // Next highest floating point number is mant+1 << exp-mantbits.
        // Our upper bound is halfway between, mant*2+1 << exp-mantbits-1.
        auto upper = new decimal{};
        rec::Assign(gocpp::recv(upper), mant * 2 + 1);
        rec::Shift(gocpp::recv(upper), exp - int(flt->mantbits) - 1);

        // d = mant << (exp - mantbits)
        // Next lowest floating point number is mant-1 << exp-mantbits,
        // unless mant-1 drops the significant bit and exp is not the minimum exp,
        // in which case the next lowest is mant*2-1 << exp-mantbits-1.
        // Either way, call it mantlo << explo-mantbits.
        // Our lower bound is halfway between, mantlo*2+1 << explo-mantbits-1.
        uint64_t mantlo = {};
        int explo = {};
        if(mant > (1 << flt->mantbits) || exp == minexp)
        {
            mantlo = mant - 1;
            explo = exp;
        }
        else
        {
            mantlo = mant * 2 - 1;
            explo = exp - 1;
        }
        auto lower = new decimal{};
        rec::Assign(gocpp::recv(lower), mantlo * 2 + 1);
        rec::Shift(gocpp::recv(lower), explo - int(flt->mantbits) - 1);

        // The upper and lower bounds are possible outputs only if
        // the original mantissa is even, so that IEEE round-to-even
        // would round to the original mantissa and not the neighbors.
        auto inclusive = mant % 2 == 0;

        // As we walk the digits we want to know whether rounding up would fall
        // within the upper bound. This is tracked by upperdelta:
        // If upperdelta == 0, the digits of d and upper are the same so far.
        // If upperdelta == 1, we saw a difference of 1 between d and upper on a
        // previous digit and subsequently only 9s for d and 0s for upper.
        // (Thus rounding up may fall outside the bound, if it is exclusive.)
        // If upperdelta == 2, then the difference is greater than 1
        // and we know that rounding up falls within the bound.
        uint8_t upperdelta = {};

        // Now we can figure out the minimum number of digits required.
        // Walk along until d has distinguished itself from upper and lower.
        for(auto ui = 0; ; ui++)
        {
            // lower, d, and upper may have the decimal points at different
            // places. In this case upper is the longest, so we iterate from
            // ui==0 and start li and mi at (possibly) -1.
            auto mi = ui - upper->dp + d->dp;
            if(mi >= d->nd)
            {
                break;
            }
            auto li = ui - upper->dp + lower->dp;
            // lower digit
            auto l = (unsigned char)('0');
            if(li >= 0 && li < lower->nd)
            {
                l = lower->d[li];
            }
            // middle digit
            auto m = (unsigned char)('0');
            if(mi >= 0)
            {
                m = d->d[mi];
            }
            // upper digit
            auto u = (unsigned char)('0');
            if(ui < upper->nd)
            {
                u = upper->d[ui];
            }

            // Okay to round down (truncate) if lower has a different digit
            // or if lower is inclusive and is exactly the result of rounding
            // down (i.e., and we have reached the final digit of lower).
            auto okdown = l != m || inclusive && li + 1 == lower->nd;

            //Go switch emulation
            {
                int conditionId = -1;
                if(upperdelta == 0 && m + 1 < u) { conditionId = 0; }
                else if(upperdelta == 0 && m != u) { conditionId = 1; }
                else if(upperdelta == 1 && (m != '9' || u != '0')) { conditionId = 2; }
                switch(conditionId)
                {
                    case 0:
                        // Example:
                        // m = 12345xxx
                        // u = 12347xxx
                        upperdelta = 2;
                        break;
                    case 1:
                        // Example:
                        // m = 12345xxx
                        // u = 12346xxx
                        upperdelta = 1;
                        break;
                    case 2:
                        // Example:
                        // m = 1234598x
                        // u = 1234600x
                        upperdelta = 2;
                        break;
                }
            }
            // Okay to round up if upper has a different digit and either upper
            // is inclusive or upper is bigger than the result of rounding up.
            auto okup = upperdelta > 0 && (inclusive || upperdelta > 1 || ui + 1 < upper->nd);

            // If it's okay to do either, then round to the nearest one.
            // If it's okay to do only one, do it.
            //Go switch emulation
            {
                int conditionId = -1;
                if(okdown && okup) { conditionId = 0; }
                else if(okdown) { conditionId = 1; }
                else if(okup) { conditionId = 2; }
                switch(conditionId)
                {
                    case 0:
                        rec::Round(gocpp::recv(d), mi + 1);
                        return;
                        break;
                    case 1:
                        rec::RoundDown(gocpp::recv(d), mi + 1);
                        return;
                        break;
                    case 2:
                        rec::RoundUp(gocpp::recv(d), mi + 1);
                        return;
                        break;
                }
            }
        }
    }

    
