    {
        return value.PrintTo(os);
    }

    // %e: -d.ddddde±dd
    gocpp::slice<unsigned char> fmtE(gocpp::slice<unsigned char> dst, bool neg, struct decimalSlice d, int prec, unsigned char fmt)
    {
        // sign
        if(neg)
        {
            dst = append(dst, '-');
        }

        // first digit
        auto ch = (unsigned char)('0');
        if(d.nd != 0)
        {
            ch = d.d[0];
        }
        dst = append(dst, ch);

        // .moredigits
        if(prec > 0)
        {
            dst = append(dst, '.');
            auto i = 1;
            auto m = gocpp::min(d.nd, prec + 1);
            if(i < m)
            {
                dst = append(dst, d.d.make_slice(i, m));
                i = m;
            }
            for(; i <= prec; i++)
            {
                dst = append(dst, '0');
            }
        }

        // e±
        dst = append(dst, fmt);
        auto exp = d.dp - 1;
        if(d.nd == 0)
        {
            // special case: 0 has exponent 0
            exp = 0;
        }
        if(exp < 0)
        {
            ch = '-';
            exp = - exp;
        }
        else
        {
            ch = '+';
        }
        dst = append(dst, ch);

        // dd or ddd
        //Go switch emulation
        {
            int conditionId = -1;
            if(exp < 10) { conditionId = 0; }
            else if(exp < 100) { conditionId = 1; }
            switch(conditionId)
            {
                case 0:
                    dst = append(dst, '0', (unsigned char)(exp) + '0');
                    break;
                case 1:
                    dst = append(dst, (unsigned char)(exp / 10) + '0', (unsigned char)(exp % 10) + '0');
                    break;
                default:
                    dst = append(dst, (unsigned char)(exp / 100) + '0', (unsigned char)(exp / 10) % 10 + '0', (unsigned char)(exp % 10) + '0');
                    break;
            }
        }

        return dst;
    }

    // %f: -ddddddd.ddddd
    gocpp::slice<unsigned char> fmtF(gocpp::slice<unsigned char> dst, bool neg, struct decimalSlice d, int prec)
    {
        // sign
        if(neg)
        {
            dst = append(dst, '-');
        }

        // integer, padded with zeros as needed.
        if(d.dp > 0)
        {
            auto m = gocpp::min(d.nd, d.dp);
            dst = append(dst, d.d.make_slice(0, m));
            for(; m < d.dp; m++)
            {
                dst = append(dst, '0');
            }
        }
        else
        {
            dst = append(dst, '0');
        }

        // fraction
        if(prec > 0)
        {
            dst = append(dst, '.');
            for(auto i = 0; i < prec; i++)
            {
                auto ch = (unsigned char)('0');
                if(auto j = d.dp + i; 0 <= j && j < d.nd)
                {
                    ch = d.d[j];
                }
                dst = append(dst, ch);
            }
        }

        return dst;
    }

    // %b: -ddddddddp±ddd
    gocpp::slice<unsigned char> fmtB(gocpp::slice<unsigned char> dst, bool neg, uint64_t mant, int exp, struct floatInfo* flt)
    {
        // sign
        if(neg)
        {
            dst = append(dst, '-');
        }

        // mantissa
        std::tie(dst, std::ignore) = formatBits(dst, mant, 10, false, true);

        // p
        dst = append(dst, 'p');

        // ±exponent
        exp -= int(flt->mantbits);
        if(exp >= 0)
        {
            dst = append(dst, '+');
        }
        std::tie(dst, std::ignore) = formatBits(dst, uint64_t(exp), 10, exp < 0, true);

        return dst;
    }

